1	//! Unicode pretty-printer for trace formulas, calibrated from the oracle
2	//! (e.g. ks1 lemma L2 -> "∀ x #i #j. (Act( x ) @ #i) ⇒ (x = x)").
3	//!
4	//! `pp_formula` renders on a single line (byte-exact when the oracle keeps the
5	//! formula on one line). `pp_formula_wrapped` reproduces the oracle's multi-line
6	//! layout for wide formulas via a small HughesPJ-style document engine
7	//! (calibrated against probes r3_gw / r3_qm): a binary connective breaks after
8	//! its operator with the right operand hanging at the connective's starting
9	//! column, and a quantifier breaks after the `.` with its body hanging two
10	//! columns past the formula's base indent. See BEHAVIOR.md.
11	
12	use crate::ast::*;
13	use crate::pretty::{pp_fact, pp_term};
14	
15	pub fn pp_formula(f: &Formula) -> String {
16	    match f {
17	        Formula::False => "⊥".to_string(),
18	        Formula::True => "⊤".to_string(),
19	        Formula::Atom(a) => pp_atom(a),
20	        Formula::Not(g) => format!("¬({})", pp_formula(g)),
21	        Formula::And(a, b) => format!("({}) ∧ ({})", pp_formula(a), pp_formula(b)),
22	        Formula::Or(a, b) => format!("({}) ∨ ({})", pp_formula(a), pp_formula(b)),
23	        Formula::Implies(a, b) => format!("({}) ⇒ ({})", pp_formula(a), pp_formula(b)),
24	        Formula::Iff(a, b) => format!("({}) ⇔ ({})", pp_formula(a), pp_formula(b)),
25	        Formula::Forall(vs, g) => format!("∀ {}. {}", pp_bound_vars(vs), pp_formula(g)),
26	        Formula::Exists(vs, g) => format!("∃ {}. {}", pp_bound_vars(vs), pp_formula(g)),
27	    }
28	}
29	
30	fn pp_bound_vars(vs: &[VarSpec]) -> String {
31	    vs.iter()
32	        .map(crate::pretty::pp_var)
33	        .collect::<Vec<_>>()
34	        .join(" ")
35	}
36	
37	fn pp_atom(a: &Atom) -> String {
38	    match a {
39	        Atom::Eq(x, y) => format!("{} = {}", pp_term(x), pp_term(y)),
40	        Atom::Less(x, y) => format!("{} < {}", pp_term(x), pp_term(y)),
41	        Atom::LessMset(x, y) => format!("{} ⋖ {}", pp_term(x), pp_term(y)),
42	        Atom::Subterm(x, y) => format!("{} ⊏ {}", pp_term(x), pp_term(y)),
43	        Atom::Action(f, t) => format!("{} @ {}", pp_fact(f), pp_term(t)),
44	        Atom::Last(t) => format!("last({})", pp_term(t)),
45	        Atom::Pred(f) => pp_fact(f),
46	    }
47	}
48	
49	// ---------------------------------------------------------------------------
50	// Multi-line layout (HughesPJ-style) for wide formulas
51	// ---------------------------------------------------------------------------
52	
53	/// Effective page width for the formula printer (measured: a wide formula's
54	/// single line fits at total column 72 and breaks by 74 - probes r3_qm).
55	pub const FORMULA_WIDTH: usize = 72;
56	
57	/// A layout document. `Beside` glues children horizontally (each child's break
58	/// indent = the column where it starts, i.e. column-aligned continuation).
59	/// `Group` is an all-or-nothing break point: it is laid flat when it fits,
60	/// otherwise the first child stays on the current line and each following child
61	/// starts a new line indented `base + hang`.
62	enum Doc {
63	    Text(String),
64	    Beside(Vec<Doc>),
65	    Group(Vec<Doc>, usize),
66	}
67	
68	fn flat(d: &Doc) -> String {
69	    match d {
70	        Doc::Text(s) => s.clone(),
71	        Doc::Beside(ds) => ds.iter().map(flat).collect(),
72	        Doc::Group(ds, _) => ds.iter().map(flat).collect::<Vec<_>>().join(" "),
73	    }
74	}
75	
76	/// Lay `d` beginning at column `col`; `base` is the reference indent for hanging
77	/// breaks. Returns the rendered text (with baked-in leading spaces on
78	/// continuation lines) and the end column of the last line.
79	fn lay(d: &Doc, col: usize, base: usize, width: usize) -> (String, usize) {
80	    match d {
81	        Doc::Text(s) => (s.clone(), col + s.chars().count()),
82	        Doc::Beside(ds) => {
83	            let mut out = String::new();
84	            let mut c = col;
85	            for x in ds {
86	                // Column-aligned: a child's own hanging breaks start at `c`.
87	                let (s, e) = lay(x, c, c, width);
88	                out.push_str(&s);
89	                c = e;
90	            }
91	            (out, c)
92	        }
93	        Doc::Group(ds, hang) => {
94	            let fw = flat(d).chars().count();
95	            if col + fw <= width {
96	                // Flat: children joined by single spaces, no internal breaks.
97	                let mut out = String::new();
98	                let mut c = col;
99	                for (i, x) in ds.iter().enumerate() {
100	                    if i > 0 {
101	                        out.push(' ');
102	                        c += 1;
103	                    }
104	                    let fs = flat(x);
105	                    c += fs.chars().count();
106	                    out.push_str(&fs);
107	                }
108	                (out, c)
109	            } else {
110	                let indent = base + hang;
111	                let (s0, _) = lay(&ds[0], col, base, width);
112	                let mut out = s0;
113	                for x in &ds[1..] {
114	                    out.push('\n');
115	                    out.push_str(&" ".repeat(indent));
116	                    let (s, _) = lay(x, indent, indent, width);
117	                    out.push_str(&s);
118	                }
119	                let end = out.rsplit('\n').next().unwrap().chars().count();
120	                (out, end)
121	            }
122	        }
123	    }
124	}
125	
126	/// `(doc)` - the operand of a connective is always parenthesised.
127	fn parens(inner: Doc) -> Doc {
128	    Doc::Beside(vec![Doc::Text("(".into()), inner, Doc::Text(")".into())])
129	}
130	
131	fn binop_doc(a: &Formula, op: &str, b: &Formula) -> Doc {
132	    // sep [ (a) <op>, (b) ] : breaks after the operator, right operand hanging
133	    // at the connective's start column (hang 0).
134	    Doc::Group(
135	        vec![
136	            Doc::Beside(vec![parens(formula_doc(a)), Doc::Text(format!(" {}", op))]),
137	            parens(formula_doc(b)),
138	        ],
139	        0,
140	    )
141	}
142	
143	fn formula_doc(f: &Formula) -> Doc {
144	    match f {
145	        Formula::False => Doc::Text("⊥".into()),
146	        Formula::True => Doc::Text("⊤".into()),
147	        Formula::Atom(a) => Doc::Text(pp_atom(a)),
148	        Formula::Not(g) => Doc::Beside(vec![Doc::Text("¬".into()), parens(formula_doc(g))]),
149	        Formula::And(a, b) => binop_doc(a, "∧", b),
150	        Formula::Or(a, b) => binop_doc(a, "∨", b),
151	        Formula::Implies(a, b) => binop_doc(a, "⇒", b),
152	        Formula::Iff(a, b) => binop_doc(a, "⇔", b),
153	        Formula::Forall(vs, g) => quantifier_doc("∀", vs, g),
154	        Formula::Exists(vs, g) => quantifier_doc("∃", vs, g),
155	    }
156	}
157	
158	fn quantifier_doc(sym: &str, vs: &[VarSpec], g: &Formula) -> Doc {
159	    // sep [ "Q v1 .. vn.", body ] : breaks after the dot, body hanging two
160	    // columns past the formula base indent (hang 2).
161	    let head = format!("{} {}.", sym, pp_bound_vars(vs));
162	    Doc::Group(vec![Doc::Text(head), formula_doc(g)], 2)
163	}
164	
165	/// Render a formula the way the oracle embeds it inside `"..."` in the
166	/// guardedness report: starting at column `col`, with `base` the indentation of
167	/// the enclosing quote. Continuation lines carry their absolute indentation.
168	pub fn pp_formula_wrapped(f: &Formula, col: usize, base: usize) -> String {
169	    lay(&formula_doc(f), col, base, FORMULA_WIDTH).0
170	}
