926	/// De Bruijn index of `name` on the binder stack (outermost pushed first): the
927	/// innermost matching binder is 0. `None` if the name is not bound (free).
928	/// Binders are matched by NAME only (see BEHAVIOR.md round-2 fix).
929	fn debruijn_index(stack: &[String], name: &str) -> Option<usize> {
930	    stack
931	        .iter()
932	        .rposition(|b| b == name)
933	        .map(|pos| stack.len() - 1 - pos)
934	}
935	
936	/// Render a term in the oracle's raw "wrong form" representation.
937	fn show_wf_term(t: &Term, stack: &[String]) -> String {
938	    match t {
939	        Term::Var(v) => match debruijn_index(stack, &v.name) {
940	            Some(idx) => format!("Bound {}", idx),
941	            None => format!("Free {}", pp_var(v)),
942	        },
943	        Term::PubLit(s) => format!("'{}'", s),
944	        Term::FreshLit(s) => format!("~'{}'", s),
945	        Term::NatLit(s) => format!("%'{}'", s),
946	        Term::Number(n) => n.to_string(),
947	        Term::NumberOne => "1".to_string(),
948	        Term::NatOne => "%1".to_string(),
949	        Term::DhNeutral => "DH_neutral".to_string(),
950	        Term::App(name, args) => {
951	            if args.is_empty() {
952	                name.clone()
953	            } else {
954	                let parts: Vec<String> = args.iter().map(|a| show_wf_term(a, stack)).collect();
955	                format!("{}({})", name, parts.join(","))
956	            }
957	        }
958	        Term::AlgApp(name, a, b) => {
959	            format!("{}({},{})", name, show_wf_term(a, stack), show_wf_term(b, stack))
960	        }
961	        Term::Pair(items) => show_wf_pair(items, stack),
962	        Term::Diff(a, b) => {
963	            format!("diff({},{})", show_wf_term(a, stack), show_wf_term(b, stack))
964	        }
965	        Term::BinOp(op, a, b) => {
966	            // Raw operator function name (best-effort; AC/DH operators in
967	            // formula terms are rare - see BEHAVIOR.md gaps).
968	            let name = match op {
969	                BinOp::Exp => "exp",
970	                BinOp::Mult => "mult",
971	                BinOp::Union => "union",
972	                BinOp::Xor => "xor",
973	                BinOp::NatPlus => "tadd",
974	            };
975	            format!("{}({},{})", name, show_wf_term(a, stack), show_wf_term(b, stack))
976	        }
977	        Term::PatMatch(inner) => show_wf_term(inner, stack),
978	    }
979	}
980	
981	/// Render a tuple as right-nested binary `pair(...)` applications.
982	fn show_wf_pair(items: &[Term], stack: &[String]) -> String {
983	    match items {
984	        [] => "pair".to_string(),
985	        [only] => show_wf_term(only, stack),
986	        [head, rest @ ..] => {
987	            format!("pair({},{})", show_wf_term(head, stack), show_wf_pair(rest, stack))
