992	/// True iff `t` contains a free variable or a reducible function symbol, i.e.
993	/// the term is "of the wrong form" for a trace formula.
994	fn term_is_ill_formed(t: &Term, stack: &[String], reducible: &std::collections::BTreeSet<String>) -> bool {
995	    match t {
996	        Term::Var(v) => debruijn_index(stack, &v.name).is_none(), // free -> ill
997	        Term::PubLit(_)
998	        | Term::FreshLit(_)
999	        | Term::NatLit(_)
1000	        | Term::Number(_)
1001	        | Term::NumberOne
1002	        | Term::NatOne
1003	        | Term::DhNeutral => false,
1004	        Term::App(name, args) => {
1005	            reducible.contains(name) || args.iter().any(|a| term_is_ill_formed(a, stack, reducible))
1006	        }
1007	        Term::AlgApp(name, a, b) => {
1008	            reducible.contains(name)
1009	                || term_is_ill_formed(a, stack, reducible)
1010	                || term_is_ill_formed(b, stack, reducible)
1011	        }
1012	        Term::Pair(items) => items.iter().any(|a| term_is_ill_formed(a, stack, reducible)),
1013	        Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1014	            term_is_ill_formed(a, stack, reducible) || term_is_ill_formed(b, stack, reducible)
1015	        }
1016	        Term::PatMatch(inner) => term_is_ill_formed(inner, stack, reducible),
1017	    }
1018	}
