1107	fn formula_terms_entry(entity: &str, name: &str, terms: &[String]) -> String {
1108	    let prefix = format!("  {} `{}' uses terms of the wrong form:", entity, name);
1109	    let tokens: Vec<String> = terms.iter().map(|t| format!("`{}'", t)).collect();
1110	    let head = fill_after_prefix(&prefix, &tokens, 4, FILL_WIDTH);
1111	    format!("{}\n  \n{}", head, FORMULA_TERMS_HELP)
