1154	pub fn formula_guardedness(thy: &Theory) -> Vec<WfError> {
1155	    let mut entries: Vec<String> = Vec::new();
1156	    for it in &thy.items {
1157	        let (name, formula) = match it {
1158	            TheoryItem::Lemma(l) => (&l.name, &l.formula),
1159	            _ => continue,
1160	        };
1161	        if let Some((fail, sub)) = find_guard_failure(formula) {
1162	            let reason = match fail {
1163	                GuardFail::Unguarded(vars) => {
1164	                    let vs: Vec<String> =
1165	                        vars.iter().map(|v| format!("'{}'", pp_var(v))).collect();
1166	                    format!(
1167	                        "unguarded variable(s) {} in the subformula",
1168	                        vs.join(", ")
1169	                    )
1170	                }
1171	                GuardFail::NoImplication => {
1172	                    "universal quantifier without toplevel implication".to_string()
1173	                }
1174	            };
1175	            // The formula is embedded as `      "..."`: the quote sits at column
1176	            // 6, so the formula starts at column 7 with base indent 6.
1177	            let pp_sub = crate::formula::pp_formula_wrapped(&sub, 7, 6);
1178	            let pp_whole = crate::formula::pp_formula_wrapped(formula, 7, 6);
1179	            entries.push(format!(
1180	                "  Lemma `{}' cannot be converted to a guarded formula:\n    {}\n      \"{}\"\n    in the formula\n      \"{}\"",
1181	                name, reason, pp_sub, pp_whole
1182	            ));
1183	        }
1184	    }
1185	    if entries.is_empty() {
1186	        vec![]
1187	    } else {
1188	        vec![WfError::new(T_GUARD, entries.join("\n"))]
1189	    }
1190	}
