1192	/// Variables appearing in any Action or Pred atom anywhere in `f` (the guard
1193	/// positions). Used as a permissive over-approximation of "guarded".
1194	fn guard_vars(f: &Formula, out: &mut Vec<VarSpec>) {
1195	    match f {
1196	        Formula::Atom(Atom::Action(fact, t)) => {
1197	            collect_fact_vars(fact, out);
1198	            collect_term_vars(t, out);
1199	        }
1200	        Formula::Atom(Atom::Pred(fact)) => collect_fact_vars(fact, out),
1201	        Formula::Atom(_) | Formula::True | Formula::False => {}
1202	        Formula::Not(g) => guard_vars(g, out),
1203	        Formula::And(a, b)
1204	        | Formula::Or(a, b)
1205	        | Formula::Implies(a, b)
1206	        | Formula::Iff(a, b) => {
1207	            guard_vars(a, out);
1208	            guard_vars(b, out);
1209	        }
1210	        Formula::Forall(_, g) | Formula::Exists(_, g) => guard_vars(g, out),
1211	    }
1212	}
