1214	/// A guardedness failure and its reason.
1215	enum GuardFail {
1216	    /// A quantifier binds variables not guarded by an action fact.
1217	    Unguarded(Vec<VarSpec>),
1218	    /// A universal quantifier's body is not a top-level implication.
1219	    NoImplication,
1220	}
