1222	/// Guard variable names of a (guard) formula: the variables appearing in its
1223	/// action/predicate atoms. Matched by NAME (see free_vars_formula rationale).
1224	fn guard_var_names(f: &Formula) -> std::collections::HashSet<String> {
1225	    let mut gv = Vec::new();
1226	    guard_vars(f, &mut gv);
1227	    gv.iter().map(|v| v.name.clone()).collect()
1228	}
1229	
1230	/// Return the first guardedness failure and the failing quantifier subformula.
1231	///
1232	/// A universal quantifier is guarded only when its body is a top-level
1233	/// implication `guard ==> rest` whose antecedent's action facts bind every
1234	/// quantified variable (observed r3_gc: a conjunction/disjunction/negation body,
1235	/// or a bare atom body, all fail as "without toplevel implication"; the
1236	/// antecedent alone - not the consequent - guards the variables). Existential
1237	/// quantifiers instead take a conjunctive guard (observed: `Ex x #i. A(x) @ #i`
1238	/// is fine); an existential whose variables are not all guarded is "unguarded".
1239	fn find_guard_failure(f: &Formula) -> Option<(GuardFail, Formula)> {
1240	    match f {
1241	        Formula::Forall(vs, body) => match &**body {
1242	            Formula::Implies(guard, rest) => {
1243	                let gset = guard_var_names(guard);
1244	                let unguarded: Vec<VarSpec> = vs
1245	                    .iter()
1246	                    .filter(|v| !gset.contains(&v.name))
1247	                    .cloned()
1248	                    .collect();
1249	                if !unguarded.is_empty() {
1250	                    return Some((GuardFail::Unguarded(unguarded), f.clone()));
1251	                }
1252	                find_guard_failure(guard).or_else(|| find_guard_failure(rest))
1253	            }
1254	            _ => Some((GuardFail::NoImplication, f.clone())),
1255	        },
1256	        Formula::Exists(vs, body) => {
1257	            let gset = guard_var_names(body);
1258	            let unguarded: Vec<VarSpec> = vs
1259	                .iter()
1260	                .filter(|v| !gset.contains(&v.name))
1261	                .cloned()
1262	                .collect();
1263	            if !unguarded.is_empty() {
1264	                return Some((GuardFail::Unguarded(unguarded), f.clone()));
1265	            }
1266	            find_guard_failure(body)
1267	        }
1268	        Formula::Not(g) => find_guard_failure(g),
1269	        Formula::And(a, b)
1270	        | Formula::Or(a, b)
1271	        | Formula::Implies(a, b)
1272	        | Formula::Iff(a, b) => find_guard_failure(a).or_else(|| find_guard_failure(b)),
1273	        _ => None,
1274	    }
1275	}
