1356	/// Structural subterm test: does `small` occur as a subterm of `big`?
1357	fn is_subterm(small: &Term, big: &Term) -> bool {
1358	    if small == big {
1359	        return true;
1360	    }
1361	    match big {
1362	        Term::App(_, args) | Term::Pair(args) => args.iter().any(|a| is_subterm(small, a)),
1363	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1364	            is_subterm(small, a) || is_subterm(small, b)
1365	        }
1366	        Term::PatMatch(inner) => is_subterm(small, inner),
1367	        _ => false,
1368	    }
