1372	// 2. Fresh public constants
1373	// ---------------------------------------------------------------------------
1374	// A fresh-name literal (`~'foo'`) used directly in a rule is rejected; fresh
1375	// names must come from `Fr(~x)` premises. Constants are collected in the order
1376	// premises, conclusions, actions (observed via probe fpc_positions).
1377	pub fn fresh_public_constants(thy: &Theory) -> Vec<WfError> {
1378	    let mut entries: Vec<String> = Vec::new();
1379	    for r in protocol_rules(thy) {
1380	        let mut lits: Vec<String> = Vec::new();
1381	        for facts in [&r.premises, &r.conclusions, &r.actions] {
1382	            for f in facts {
1383	                for a in &f.args {
1384	                    collect_fresh_lits(a, &mut lits);
1385	                }
1386	            }
1387	        }
1388	        if lits.is_empty() {
1389	            continue;
1390	        }
1391	        // The constant list is a fillSep wrapped at column 69 with a 4-space
1392	        // continuation indent (probe r3_freshwrap).
1393	        let prefix = format!(
1394	            "  rule `{}': fresh public constants are not allowed:",
1395	            r.name
1396	        );
1397	        entries.push(fill_after_prefix(&prefix, &lits, 4, FILL_WIDTH));
1398	    }
1399	    if entries.is_empty() {
1400	        vec![]
1401	    } else {
1402	        vec![WfError::new(T_FRESH_PUB, entries.join("\n  \n"))]
1403	    }
1404	}

